        ip->xDD4_itemVar.pikachuthunder.x38 != NULL &&
        !ftPk_SpecialLw_CheckProperty(ip->xDD4_itemVar.pikachuthunder.x38))
    {
        ftPk_SpecialLw_SetState_Unk0(ip->xDD4_itemVar.pikachuthunder.x38);
    }
}

void it_802B2080(Item_GObj* gobj)
{
